const log = { tool: 'get_reactivation_list', input: $json, ts: new Date().toISOString() };
console.log(JSON.stringify(log));
return $input.all();

// Apenas valida e monta parâmetros. A chamada HTTP ao snapshot vai no nó HTTP Request seguinte
// para evitar o timeout de 60s do task runner do Code node.
const PANEL_BASE = 'https://longflatworm-n8n.cloudfy.live/webhook';
const input = $json || {};
const userId = String(input.user_id || '');
const limit = Math.max(1, Math.min(500, +input.limit || 50));
const uf = input.uf ? String(input.uf).trim().toUpperCase() : '';
const onlyEligible = input.only_eligible !== false;
const url = PANEL_BASE + '/castor-panel-snapshot' + (userId ? '?userId=' + encodeURIComponent(userId) : '');
return [{ json: { user_id: userId, limit, uf, only_eligible: onlyEligible, url } }];

const params = $('Prepare params').first().json;
const resp = $json || {};
if (resp.error && !resp.ok) {
  return [{ json: { ok: false, data: [], error: 'snapshot_failed: ' + (resp.error.message || resp.error) } }];
}
if (!resp || resp.ok === false) {
  return [{ json: { ok: false, data: [], error: 'snapshot_failed: ' + ((resp && resp.error) || 'snapshot indisponivel') } }];
}
const snap = resp.data || {};
const limit = params.limit, uf = params.uf, onlyEligible = params.only_eligible;
const today = new Date(); today.setUTCHours(0,0,0,0);
const rows = [];
for (const c of (snap.clientes || [])) {
  const isReact = (typeof c.elegivel_reativacao === 'boolean') ? c.elegivel_reativacao : (c.a1_ustatus === '2');
  if (!isReact) continue;
  const lf = c.last_feedback || null;
  if (lf && lf.outcome === 'convertido') continue;
  let elegivel = true, daysLeft = null;
  if (lf && lf.next_contact_at) {
    const nxt = new Date(String(lf.next_contact_at).slice(0,10) + 'T00:00:00Z');
    const diff = Math.ceil((nxt.getTime() - today.getTime()) / 86400000);
    if (diff > 0) { elegivel = false; daysLeft = diff; }
  }
  if (onlyEligible && !elegivel) continue;
  if (uf && (c.a1_est || '').toUpperCase() !== uf) continue;
  rows.push({
    cliente_codigo: c.cliente_codigo,
    a1_cod: c.a1_cod, a1_loja: c.a1_loja,
    a1_nome: c.a1_nome, a1_nreduz: c.a1_nreduz,
    a1_cgc: c.a1_cgc,
    a1_mun: c.a1_mun, a1_est: c.a1_est,
    a1_tel: c.a1_tel, a1_email: c.a1_email,
    a1_vend: c.a1_vend, vendedor_nome: c.vendedor_nome,
    porte_efetivo: c.porte_efetivo, porte_origem: c.porte_origem,
    faturamento_12m: c.faturamento_12m,
    ticket_medio_12m: c.ticket_medio_12m,
    pedidos_12m: c.pedidos_12m,
    ultimo_pedido: c.ultimo_pedido,
    dias_sem_pedido: c.dias_sem_pedido,
    ultima_visita: lf ? lf.visited_at : null,
    proximo_contato: lf ? lf.next_contact_at : null,
    elegivel_agora: elegivel,
    days_until_recall: daysLeft
  });
}
rows.sort((a,b) =>
  (b.faturamento_12m || 0) - (a.faturamento_12m || 0) ||
  (b.pedidos_12m || 0) - (a.pedidos_12m || 0) ||
  String(a.cliente_codigo).localeCompare(String(b.cliente_codigo))
);
for (let i = 0; i < rows.length; i++) rows[i].priority_rank = i + 1;
const sliced = rows.slice(0, limit);
return [{ json: { ok: true, data: sliced, error: null, meta: { total: rows.length, returned: sliced.length, source: 'snapshot', generated_at: snap.generated_at } } }];
